var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"……씨!","JPN":"……様！","ENG":"–up!","TWN":"……姐！"},"stage":{"bg":"black","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"……아가씨!","JPN":"……お嬢様！","ENG":"...Miss Jia, wake up!","TWN":"……小姐！"},"stage":{"bg":"black","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨, 다행이에요. 정신이 드셨군요.","JPN":"お嬢様、よかったです。気がつきましたか。","ENG":"Thank goodness. You’re awake.","TWN":"小姐，太好了，你終於醒了。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이진 언니……. 여긴…….","JPN":"ホノカさん……ここは……","ENG":"Jin...? W-where am I...?","TWN":"李珍姐……這裡是……"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그룹에서 보낸 헬기 안입니다. 아가씨께서 쓰러지셔서 병원으로 가던 참이었어요.","JPN":"グループから送られたヘリの中です。\\nお嬢様が倒れてしまったので、病院に向かうところです。","ENG":"You’re inside a helicopter. You fainted, so we were on our way to the hospital.","TWN":"我們在集團派來的直升機裡，小姐剛暈過去了，所以正在帶小姐去醫院的路上。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"쓰러졌나요, 제가……?","JPN":"倒れてしまったのですか、私が……？","ENG":"I-I fainted...?","TWN":"我暈過去了嗎……？"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"고모님은…… 바이오닉스 대표는 어떻게 됐죠?","JPN":"叔母様は……バイオニクス代表はどうなりました？","ENG":"And what about Auntie, I mean, the CEO of Bionics?","TWN":"那姑姑……仿生代表呢？"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"죄송합니다. 바이오닉스 대표는 아가씨의 클론들이 제압당하는 동안 도주한 모양입니다.","JPN":"申し訳ございません。バイオニクス代表は、お嬢様のクローンたちが\\n制圧されている隙に逃走したようです。","ENG":"My apologies. We lost her while we were preoccupied with taking down the clones.","TWN":"抱歉，她趁小姐在對付複製人時逃跑了。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"다른 분들은……. 모두 무사하신가요?","JPN":"他の方々は……みんなご無事ですか？","ENG":"Everyone else...? Are they okay?","TWN":"其他人……都沒事吧？"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"네, 리더. 다들 실컷 날뛰고 뻗어 있어요.","JPN":"はい、リーダー。みんなひと暴れした後なので眠っています。","ENG":"Yes, Leader. They’re snoozing over there after rampaging all over the place.","TWN":"是，老大。大家都還能跑能跳。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"음냐아……. 스포트라이트……. 잔뜩 받고 있어…….","JPN":"むにゃ……スポットライト……いっぱい当たっている……","ENG":"Myah... The limelight... It’s on me...","TWN":"哇……聚光燈……只照我欸……"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"마침내 손에 넣었다……. 칠색의 파사검……!","JPN":"ついに手に入れた……七色の破邪剣……！","ENG":"I finally got it... the Iridescent Evil-fighting Greatsword...!","TWN":"終於落到我手裡……七色破邪劍……！"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"오새롬 전용 바이크라니……. 에헤헤…….","JPN":"アサネ専用バイクだぁ……えへへ……","ENG":"An Oh Saerom-exclusive bike...? Heh heh...","TWN":"吳芷倫專屬腳踏車……嘿嘿嘿……"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"CRF의 정식 명칭이 현실개변력인 건 알고 있지만…….","JPN":"CRFの正式名称が現実改変力であることは知っていましたが……","ENG":"I knew CRF stood for Counter Reality Force...","TWN":"據我所知，CRF的正式名稱為現實改變力……"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"아무리 그래도 설마 다른 사람들의 상상까지 현실에 그대로 구현할 수 있을 줄은 몰랐어요.","JPN":"いくらなんでも、まさか他人の想像までそのまま現実に具現化できるとは\\n思いもしませんでした。","ENG":"But I never thought you could turn another person’s imagination into reality like that.","TWN":"但沒想到，可以在現實中實現其他人的想像。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};